module shift_register_8bit(
    input clk,
    input rst,
    input data_in,
    output reg [7:0] data_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    if (rst)
        data_out <= 8'b00000000;
    else
        data_out <= {data_in, data_out[7:1]};

endmodule
